/**
 * @file admin-auth.service.ts
 * @description Business logic for admin authentication.
 * @module src/modules/admin-auth/admin-auth.service
 */
import { AppError } from '@/shared/errors/AppError.js';
import { redis } from '@/shared/infrastructure/redis.js';
import { comparePassword } from '@/shared/utils/hash.js';
import { getTokenRemainingTtl, signToken, verifyToken } from '@/shared/utils/token.js';
import { validateEmail } from '@/shared/domain/value-objects/Email.js';

import { adminAuthRepository } from './admin-auth.repository.js';
import type { IAdminLogin, IAdminSessionResponse } from './admin-auth.schema.js';

export const adminAuthService = {
  async login(input: IAdminLogin): Promise<IAdminSessionResponse> {
    const email = validateEmail(input.email);

    const admin = await adminAuthRepository.findAdminByEmail(email);
    if (!admin) {
      throw new AppError('INVALID_CREDENTIALS', 'Invalid email or password.', 401);
    }

    const isPasswordValid = await comparePassword(input.password, admin.passwordHash);
    if (!isPasswordValid) {
      throw new AppError('INVALID_CREDENTIALS', 'Invalid email or password.', 401);
    }

    const accessToken = signToken({
      sub: admin.id,
      email: admin.email,
      role: admin.role,
    });

    return {
      accessToken,
      role: 'admin',
      user: {
        id: admin.id,
        email: admin.email,
        firstName: admin.firstName,
        lastName: admin.lastName,
        role: 'admin',
      },
    };
  },

  async logout(token: string): Promise<{ message: string }> {
    const decoded = verifyToken(token);
    const ttl = getTokenRemainingTtl(decoded);

    if (ttl > 0) {
      await redis.set(`token:blacklist:${decoded.jti}`, '1', 'EX', ttl);
    }

    return { message: 'Logged out successfully.' };
  },
};

/**
 * @file admin-bookings.routes.ts
 * @description Admin bookings management — list, filter, view, update. Requires ADMIN role.
 * @module src/modules/admin-bookings/admin-bookings.routes
 */
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import fp from 'fastify-plugin';
import { z } from 'zod';

import { BOOKING_STATUS_MAP } from '@/modules/bookings/bookings.schema.js';
import { AppError } from '@/shared/errors/AppError.js';
import { prisma } from '@/shared/infrastructure/prisma.js';
import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

const adminGuard = [authMiddleware, requireRole('ADMIN')];

const BookingIdParamSchema = z.object({ bookingId: z.string().min(1) });
const UpdateBookingSchema = z.object({
  status: z.enum(['PENDING', 'CONFIRMED', 'CANCELLED']),
});

const bookingSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    userId: { type: 'string' },
    userEmail: { type: 'string' },
    serviceName: { type: 'string' },
    date: { type: 'string' },
    time: { type: 'string' },
    location: { type: 'string' },
    status: { type: 'string', enum: ['confirmed', 'pending', 'cancelled'] },
    price: { type: 'number' },
    createdAt: { type: 'string' },
  },
};

async function adminBookingsRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/admin/bookings', {
    schema: {
      tags: ['Admin'],
      summary: 'List all bookings with optional filters and pagination',
      security: [{ BearerAuth: [] }],
      querystring: {
        type: 'object',
        properties: {
          status: { type: 'string', enum: ['PENDING', 'CONFIRMED', 'CANCELLED'] },
          userId: { type: 'string' },
          page: { type: 'integer', default: 1 },
          pageSize: { type: 'integer', default: 20 },
        },
      },
      response: {
        200: {
          type: 'object',
          properties: {
            data: { type: 'array', items: bookingSchema },
            page: { type: 'integer' },
            pageSize: { type: 'integer' },
            total: { type: 'integer' },
            totalPages: { type: 'integer' },
          },
        },
      },
    },
    preHandler: adminGuard,
    handler: async (
      request: FastifyRequest<{ Querystring: { status?: string; userId?: string; page?: number; pageSize?: number } }>,
      reply: FastifyReply,
    ) => {
      const { status, userId, page = 1, pageSize = 20 } = request.query;
      const skip = (page - 1) * pageSize;

      const where = {
        ...(status && { status: status as 'PENDING' | 'CONFIRMED' | 'CANCELLED' }),
        ...(userId && { userId }),
      };

      const [bookings, total] = await Promise.all([
        prisma.booking.findMany({
          where,
          include: { session: { include: { service: true } }, user: true },
          skip,
          take: pageSize,
          orderBy: { createdAt: 'desc' },
        }),
        prisma.booking.count({ where }),
      ]);

      await reply.status(200).send({
        data: bookings.map((b) => ({
          id: b.id,
          userId: b.userId,
          userEmail: b.user.email,
          serviceName: b.session.service.title,
          date: b.session.date.toISOString(),
          time: b.session.time,
          location: b.session.location,
          status: BOOKING_STATUS_MAP[b.status],
          price: (b.price).toNumber(),
          createdAt: b.createdAt.toISOString(),
        })),
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      });
    },
  });

  app.get('/api/v1/admin/bookings/:bookingId', {
    schema: {
      tags: ['Admin'],
      summary: 'Get full booking detail by ID',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { bookingId: { type: 'string' } } },
      response: { 200: bookingSchema },
    },
    preHandler: [...adminGuard, validate({ params: BookingIdParamSchema })],
    handler: async (
      request: FastifyRequest<{ Params: { bookingId: string } }>,
      reply: FastifyReply,
    ) => {
      const booking = await prisma.booking.findUnique({
        where: { id: request.params.bookingId },
        include: { session: { include: { service: true } }, user: true },
      });
      if (!booking) throw new AppError('BOOKING_NOT_FOUND', 'Booking not found.', 404);

      await reply.status(200).send({
        id: booking.id,
        userId: booking.userId,
        userEmail: booking.user.email,
        serviceName: booking.session.service.title,
        date: booking.session.date.toISOString(),
        time: booking.session.time,
        location: booking.session.location,
        status: BOOKING_STATUS_MAP[booking.status],
        price: (booking.price).toNumber(),
        createdAt: booking.createdAt.toISOString(),
      });
    },
  });

  app.patch('/api/v1/admin/bookings/:bookingId', {
    schema: {
      tags: ['Admin'],
      summary: 'Update booking status',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { bookingId: { type: 'string' } } },
      body: {
        type: 'object',
        required: ['status'],
        properties: { status: { type: 'string', enum: ['PENDING', 'CONFIRMED', 'CANCELLED'] } },
      },
      response: { 200: bookingSchema },
    },
    preHandler: [
      ...adminGuard,
      validate({ params: BookingIdParamSchema, body: UpdateBookingSchema }),
    ],
    handler: async (
      request: FastifyRequest<{ Params: { bookingId: string }; Body: { status: 'PENDING' | 'CONFIRMED' | 'CANCELLED' } }>,
      reply: FastifyReply,
    ) => {
      const existing = await prisma.booking.findUnique({ where: { id: request.params.bookingId } });
      if (!existing) throw new AppError('BOOKING_NOT_FOUND', 'Booking not found.', 404);

      const booking = await prisma.booking.update({
        where: { id: request.params.bookingId },
        data: {
          status: request.body.status,
          ...(request.body.status === 'CANCELLED' && { cancelledAt: new Date() }),
        },
        include: { session: { include: { service: true } }, user: true },
      });

      await reply.status(200).send({
        id: booking.id,
        userId: booking.userId,
        userEmail: booking.user.email,
        serviceName: booking.session.service.title,
        date: booking.session.date.toISOString(),
        time: booking.session.time,
        location: booking.session.location,
        status: BOOKING_STATUS_MAP[booking.status],
        price: (booking.price).toNumber(),
        createdAt: booking.createdAt.toISOString(),
      });
    },
  });
}

export default fp(adminBookingsRoutes, { name: 'admin-bookings-routes' });

/**
 * @file admin-dashboard.routes.ts
 * @description Admin dashboard — summary statistics. Requires ADMIN role.
 * @module src/modules/admin-dashboard/admin-dashboard.routes
 */
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import fp from 'fastify-plugin';

import { prisma } from '@/shared/infrastructure/prisma.js';
import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';

const adminGuard = [authMiddleware, requireRole('ADMIN')];

async function adminDashboardRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/admin/dashboard', {
    schema: {
      tags: ['Admin'],
      summary: 'Admin dashboard — summary stats',
      security: [{ BearerAuth: [] }],
      response: {
        200: {
          type: 'object',
          properties: {
            totalUsers: { type: 'integer' },
            totalBookings: { type: 'integer' },
            confirmedBookings: { type: 'integer' },
            cancelledBookings: { type: 'integer' },
            totalRevenue: { type: 'number' },
            activeSessions: { type: 'integer' },
            pendingRefunds: { type: 'integer' },
          },
        },
      },
    },
    preHandler: adminGuard,
    handler: async (_request: FastifyRequest, reply: FastifyReply) => {
      const [
        totalUsers,
        totalBookings,
        confirmedBookings,
        cancelledBookings,
        revenueResult,
        activeSessions,
        pendingRefunds,
      ] = await Promise.all([
        prisma.user.count({ where: { role: { in: ['PARENT', 'SCHOOL'] } } }),
        prisma.booking.count(),
        prisma.booking.count({ where: { status: 'CONFIRMED' } }),
        prisma.booking.count({ where: { status: 'CANCELLED' } }),
        prisma.payment.aggregate({ _sum: { amount: true }, where: { status: 'PAID' } }),
        prisma.session.count({ where: { isActive: true } }),
        prisma.refund.count({ where: { status: 'PENDING' } }),
      ]);

      await reply.status(200).send({
        totalUsers,
        totalBookings,
        confirmedBookings,
        cancelledBookings,
        totalRevenue: revenueResult._sum.amount?.toNumber() ?? 0,
        activeSessions,
        pendingRefunds,
      });
    },
  });
}

export default fp(adminDashboardRoutes, { name: 'admin-dashboard-routes' });

/**
 * @file admin-knowledge.routes.ts
 * @description Admin knowledge/CMS management — CRUD for case studies, free activities, FAQs.
 * Requires ADMIN role.
 * @module src/modules/admin-knowledge/admin-knowledge.routes
 */
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import fp from 'fastify-plugin';
import { z } from 'zod';

import { AppError } from '@/shared/errors/AppError.js';
import { prisma } from '@/shared/infrastructure/prisma.js';
import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

const adminGuard = [authMiddleware, requireRole('ADMIN')];
const IdParamSchema = z.object({ id: z.string().min(1) });

const CaseStudyCreateSchema = z.object({
  title: z.string().min(1),
  body: z.string().min(1),
  tag: z.string().optional(),
  order: z.number().int().optional(),
});

const CaseStudyUpdateSchema = CaseStudyCreateSchema.partial().extend({
  isActive: z.boolean().optional(),
});

const FreeActivityCreateSchema = z.object({
  title: z.string().min(1),
  description: z.string().min(1),
  downloads: z.array(z.string().url()).min(1),
  order: z.number().int().optional(),
});

const FreeActivityUpdateSchema = z.object({
  title: z.string().optional(),
  description: z.string().optional(),
  isActive: z.boolean().optional(),
  order: z.number().int().optional(),
});

const FaqGroupCreateSchema = z.object({
  title: z.string().min(1),
  order: z.number().int().optional(),
  items: z.array(z.object({
    question: z.string().min(1),
    answer: z.string().min(1),
    order: z.number().int().optional(),
  })).min(1),
});

const FaqGroupUpdateSchema = z.object({
  title: z.string().optional(),
  order: z.number().int().optional(),
  isActive: z.boolean().optional(),
});

async function adminKnowledgeRoutes(app: FastifyInstance): Promise<void> {
  // ─── Case Studies ─────────────────────────────────────────────────────────

  app.post('/api/v1/admin/knowledge/case-studies', {
    schema: { tags: ['Admin'], summary: 'Create a case study', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ body: CaseStudyCreateSchema })],
    handler: async (request: FastifyRequest<{ Body: z.infer<typeof CaseStudyCreateSchema> }>, reply: FastifyReply) => {
      const cs = await prisma.caseStudy.create({ data: request.body });
      await reply.status(201).send(cs);
    },
  });

  app.patch('/api/v1/admin/knowledge/case-studies/:id', {
    schema: { tags: ['Admin'], summary: 'Update a case study', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ params: IdParamSchema, body: CaseStudyUpdateSchema })],
    handler: async (request: FastifyRequest<{ Params: { id: string }; Body: z.infer<typeof CaseStudyUpdateSchema> }>, reply: FastifyReply) => {
      const existing = await prisma.caseStudy.findUnique({ where: { id: request.params.id } });
      if (!existing) throw new AppError('ACCOUNT_NOT_FOUND', 'Case study not found.', 404);
      const cs = await prisma.caseStudy.update({ where: { id: request.params.id }, data: request.body });
      await reply.status(200).send(cs);
    },
  });

  app.delete('/api/v1/admin/knowledge/case-studies/:id', {
    schema: { tags: ['Admin'], summary: 'Delete (deactivate) a case study', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ params: IdParamSchema })],
    handler: async (request: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
      const existing = await prisma.caseStudy.findUnique({ where: { id: request.params.id } });
      if (!existing) throw new AppError('ACCOUNT_NOT_FOUND', 'Case study not found.', 404);
      await prisma.caseStudy.update({ where: { id: request.params.id }, data: { isActive: false } });
      await reply.status(204).send();
    },
  });

  // ─── Free Activities ──────────────────────────────────────────────────────

  app.post('/api/v1/admin/knowledge/free-activities', {
    schema: { tags: ['Admin'], summary: 'Create a free activity group', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ body: FreeActivityCreateSchema })],
    handler: async (request: FastifyRequest<{ Body: z.infer<typeof FreeActivityCreateSchema> }>, reply: FastifyReply) => {
      const { downloads, ...groupData } = request.body;
      const group = await prisma.freeActivityGroup.create({
        data: {
          ...groupData,
          downloads: { create: downloads.map((url) => ({ url })) },
        },
        include: { downloads: true },
      });
      await reply.status(201).send(group);
    },
  });

  app.patch('/api/v1/admin/knowledge/free-activities/:id', {
    schema: { tags: ['Admin'], summary: 'Update a free activity group', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ params: IdParamSchema, body: FreeActivityUpdateSchema })],
    handler: async (request: FastifyRequest<{ Params: { id: string }; Body: z.infer<typeof FreeActivityUpdateSchema> }>, reply: FastifyReply) => {
      const existing = await prisma.freeActivityGroup.findUnique({ where: { id: request.params.id } });
      if (!existing) throw new AppError('ACCOUNT_NOT_FOUND', 'Free activity not found.', 404);
      const group = await prisma.freeActivityGroup.update({ where: { id: request.params.id }, data: request.body, include: { downloads: true } });
      await reply.status(200).send(group);
    },
  });

  app.delete('/api/v1/admin/knowledge/free-activities/:id', {
    schema: { tags: ['Admin'], summary: 'Delete (deactivate) a free activity group', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ params: IdParamSchema })],
    handler: async (request: FastifyRequest<{ Params: { id: string } }>, reply: FastifyReply) => {
      const existing = await prisma.freeActivityGroup.findUnique({ where: { id: request.params.id } });
      if (!existing) throw new AppError('ACCOUNT_NOT_FOUND', 'Free activity not found.', 404);
      await prisma.freeActivityGroup.update({ where: { id: request.params.id }, data: { isActive: false } });
      await reply.status(204).send();
    },
  });

  // ─── FAQs ─────────────────────────────────────────────────────────────────

  app.post('/api/v1/admin/faqs', {
    schema: { tags: ['Admin'], summary: 'Create a FAQ group with items', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ body: FaqGroupCreateSchema })],
    handler: async (request: FastifyRequest<{ Body: z.infer<typeof FaqGroupCreateSchema> }>, reply: FastifyReply) => {
      const { items, ...groupData } = request.body;
      const group = await prisma.faqGroup.create({
        data: {
          ...groupData,
          items: { create: items },
        },
        include: { items: true },
      });
      await reply.status(201).send(group);
    },
