  app.patch('/api/v1/admin/faqs/:id', {
    schema: { tags: ['Admin'], summary: 'Update a FAQ group', security: [{ BearerAuth: [] }] },
    preHandler: [...adminGuard, validate({ params: IdParamSchema, body: FaqGroupUpdateSchema })],
