}

export default fp(adminKnowledgeRoutes, { name: 'admin-knowledge-routes' });

/**
 * @file admin-payments.routes.ts
 * @description Admin payments management — list, view, trigger refunds. Requires ADMIN role.
 * @module src/modules/admin-payments/admin-payments.routes
 */
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import fp from 'fastify-plugin';
import { z } from 'zod';

import { PAYMENT_STATUS_MAP } from '@/modules/payments/payments.schema.js';
import { refundsService } from '@/modules/refunds/refunds.service.js';
import { AppError } from '@/shared/errors/AppError.js';
import { prisma } from '@/shared/infrastructure/prisma.js';
import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

const adminGuard = [authMiddleware, requireRole('ADMIN')];
const PaymentIdParamSchema = z.object({ paymentId: z.string().min(1) });
const AdminRefundSchema = z.object({
  amount: z.number().positive(),
  reason: z.string().min(1),
});

const paymentSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    bookingId: { type: 'string' },
    userEmail: { type: 'string' },
    amount: { type: 'number' },
    currency: { type: 'string' },
    status: { type: 'string' },
    stripePaymentIntentId: { type: 'string' },
    createdAt: { type: 'string' },
  },
};

async function adminPaymentsRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/admin/payments', {
    schema: {
      tags: ['Admin'],
      summary: 'List all payments with optional filters and pagination',
      security: [{ BearerAuth: [] }],
      querystring: {
        type: 'object',
        properties: {
          status: { type: 'string', enum: ['PENDING', 'PAID', 'REFUNDED', 'FAILED'] },
          page: { type: 'integer', default: 1 },
          pageSize: { type: 'integer', default: 20 },
        },
      },
      response: {
        200: {
          type: 'object',
          properties: {
            data: { type: 'array', items: paymentSchema },
            page: { type: 'integer' },
            pageSize: { type: 'integer' },
            total: { type: 'integer' },
            totalPages: { type: 'integer' },
          },
        },
      },
    },
    preHandler: adminGuard,
    handler: async (
      request: FastifyRequest<{ Querystring: { status?: string; page?: number; pageSize?: number } }>,
      reply: FastifyReply,
    ) => {
      const { status, page = 1, pageSize = 20 } = request.query;
      const skip = (page - 1) * pageSize;
      const where = status ? { status: status as 'PENDING' | 'PAID' | 'REFUNDED' | 'FAILED' } : {};

      const [payments, total] = await Promise.all([
        prisma.payment.findMany({
          where,
          include: { booking: { include: { user: true } } },
          skip,
          take: pageSize,
          orderBy: { createdAt: 'desc' },
        }),
        prisma.payment.count({ where }),
      ]);

      await reply.status(200).send({
        data: payments.map((p) => ({
          id: p.id,
          bookingId: p.bookingId,
          userEmail: p.booking.user.email,
          amount: (p.amount).toNumber(),
          currency: p.currency,
          status: PAYMENT_STATUS_MAP[p.status],
          stripePaymentIntentId: p.stripePaymentIntentId,
          createdAt: p.createdAt.toISOString(),
        })),
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      });
    },
  });

  app.get('/api/v1/admin/payments/:paymentId', {
    schema: {
      tags: ['Admin'],
      summary: 'Get payment detail by ID',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { paymentId: { type: 'string' } } },
      response: { 200: paymentSchema },
    },
    preHandler: [...adminGuard, validate({ params: PaymentIdParamSchema })],
    handler: async (
      request: FastifyRequest<{ Params: { paymentId: string } }>,
      reply: FastifyReply,
    ) => {
      const payment = await prisma.payment.findUnique({
        where: { id: request.params.paymentId },
        include: { booking: { include: { user: true } } },
      });
      if (!payment) throw new AppError('ACCOUNT_NOT_FOUND', 'Payment not found.', 404);

      await reply.status(200).send({
        id: payment.id,
        bookingId: payment.bookingId,
        userEmail: payment.booking.user.email,
        amount: (payment.amount).toNumber(),
        currency: payment.currency,
        status: PAYMENT_STATUS_MAP[payment.status],
        stripePaymentIntentId: payment.stripePaymentIntentId,
        createdAt: payment.createdAt.toISOString(),
      });
    },
  });

  app.post('/api/v1/admin/payments/:paymentId/refund', {
    schema: {
      tags: ['Admin'],
      summary: 'Trigger a refund for a payment',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { paymentId: { type: 'string' } } },
      body: {
        type: 'object',
        required: ['amount', 'reason'],
        properties: {
          amount: { type: 'number', description: 'Amount in GBP' },
          reason: { type: 'string' },
        },
      },
      response: {
        201: {
          type: 'object',
          properties: {
            id: { type: 'string' },
            paymentId: { type: 'string' },
            amount: { type: 'number' },
            reason: { type: 'string' },
            status: { type: 'string' },
            createdAt: { type: 'string' },
          },
        },
      },
    },
    preHandler: [
      ...adminGuard,
      validate({ params: PaymentIdParamSchema, body: AdminRefundSchema }),
    ],
    handler: async (
      request: FastifyRequest<{ Params: { paymentId: string }; Body: { amount: number; reason: string } }>,
      reply: FastifyReply,
    ) => {
      const refund = await refundsService.createRefund({
        paymentId: request.params.paymentId,
        amount: request.body.amount,
        reason: request.body.reason,
      });
      await reply.status(201).send(refund);
    },
  });
}

export default fp(adminPaymentsRoutes, { name: 'admin-payments-routes' });

/**
 * @file admin-roles.routes.ts
 * @description Admin roles management — manage admin users. Requires ADMIN role.
 * @module src/modules/admin-roles/admin-roles.routes
 */
import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify';
import fp from 'fastify-plugin';
import { z } from 'zod';

import { AppError } from '@/shared/errors/AppError.js';
import { prisma } from '@/shared/infrastructure/prisma.js';
import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';
import { validate } from '@/shared/middleware/validate.js';
import { hashPassword } from '@/shared/utils/hash.js';

const adminGuard = [authMiddleware, requireRole('ADMIN')];
const UserIdParamSchema = z.object({ userId: z.string().min(1) });

const CreateAdminUserSchema = z.object({
  email: z.string().email(),
  password: z.string().min(8),
  firstName: z.string().min(1),
  lastName: z.string().min(1),
});

const adminUserSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    email: { type: 'string' },
    firstName: { type: 'string' },
    lastName: { type: 'string' },
    role: { type: 'string' },
    createdAt: { type: 'string' },
  },
};

async function adminRolesRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/admin/users', {
    schema: {
      tags: ['Admin'],
      summary: 'List all admin users',
      security: [{ BearerAuth: [] }],
      response: { 200: { type: 'array', items: adminUserSchema } },
    },
    preHandler: adminGuard,
    handler: async (_request: FastifyRequest, reply: FastifyReply) => {
      const admins = await prisma.user.findMany({
        where: { role: 'ADMIN' },
        select: { id: true, email: true, firstName: true, lastName: true, role: true, createdAt: true },
        orderBy: { createdAt: 'asc' },
      });
      await reply.status(200).send(
        admins.map((a) => ({ ...a, role: 'admin', createdAt: a.createdAt.toISOString() })),
      );
    },
  });

  app.post('/api/v1/admin/users', {
    schema: {
      tags: ['Admin'],
      summary: 'Create a new admin user',
      security: [{ BearerAuth: [] }],
      response: { 201: adminUserSchema },
    },
    preHandler: [...adminGuard, validate({ body: CreateAdminUserSchema })],
    handler: async (
      request: FastifyRequest<{ Body: z.infer<typeof CreateAdminUserSchema> }>,
      reply: FastifyReply,
    ) => {
      const { email, password, firstName, lastName } = request.body;

      const existing = await prisma.user.findUnique({ where: { email } });
      if (existing) {
        throw new AppError('EMAIL_ALREADY_EXISTS', 'An account with this email already exists.', 409);
      }

      const passwordHash = await hashPassword(password);
      const user = await prisma.user.create({
        data: { email, passwordHash, firstName, lastName, role: 'ADMIN' },
        select: { id: true, email: true, firstName: true, lastName: true, role: true, createdAt: true },
      });

      await reply.status(201).send({ ...user, role: 'admin', createdAt: user.createdAt.toISOString() });
    },
  });

  app.delete('/api/v1/admin/users/:userId', {
    schema: {
      tags: ['Admin'],
      summary: 'Remove an admin user (cannot remove yourself)',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { userId: { type: 'string' } } },
      response: { 204: { type: 'null' } },
    },
    preHandler: [...adminGuard, validate({ params: UserIdParamSchema })],
    handler: async (
      request: FastifyRequest<{ Params: { userId: string } }>,
      reply: FastifyReply,
    ) => {
      if (request.params.userId === request.user!.id) {
        throw new AppError('VALIDATION_ERROR', 'You cannot remove your own admin account.', 422);
      }

      const user = await prisma.user.findFirst({
        where: { id: request.params.userId, role: 'ADMIN' },
      });
      if (!user) throw new AppError('ACCOUNT_NOT_FOUND', 'Admin user not found.', 404);

      await prisma.user.delete({ where: { id: request.params.userId } });
      await reply.status(204).send();
    },
  });
}

export default fp(adminRolesRoutes, { name: 'admin-roles-routes' });

