/**
 * @file children.domain.ts
 * @description Pure domain logic for children. No Prisma, no side effects.
 * @module src/modules/children/children.domain
 */
import type { IChildResponse } from './children.schema.js';

export function mapToChildResponse(child: {
  id: string;
  firstName: string;
  lastName: string;
  dateOfBirth: Date;
  gender: string;
  yearGroup: string;
  medicalConditions: string | null;
}): IChildResponse {
  return {
    id: child.id,
    firstName: child.firstName,
    lastName: child.lastName,
    dateOfBirth: child.dateOfBirth.toISOString().split('T')[0]!,
    gender: child.gender,
    yearGroup: child.yearGroup,
    ...(child.medicalConditions && { medicalConditions: child.medicalConditions }),
  };
}

/**
 * @file children.repository.ts
 * @description Data access layer for children and emergency contacts.
 * @module src/modules/children/children.repository
 */
import { prisma } from '@/shared/infrastructure/prisma.js';
import type { IEmergencyContact } from './children.schema.js';

interface CreateChildData {
  userId: string;
  firstName: string;
  lastName: string;
  dateOfBirth: Date;
  gender: string;
  yearGroup: string;
  medicalConditions?: string;
  emergencyContacts: IEmergencyContact[];
}

interface UpdateChildData {
  firstName?: string;
  lastName?: string;
  dateOfBirth?: Date;
  gender?: string;
  yearGroup?: string;
  medicalConditions?: string;
}

export const childrenRepository = {
  async findAllByUserId(userId: string) {
    return prisma.child.findMany({
      where: { userId },
      orderBy: { createdAt: 'asc' },
    });
  },

  async findByIdAndUserId(childId: string, userId: string) {
    return prisma.child.findFirst({
      where: { id: childId, userId },
    });
  },

  async create(data: CreateChildData) {
    return prisma.child.create({
      data: {
        userId: data.userId,
        firstName: data.firstName,
        lastName: data.lastName,
        dateOfBirth: data.dateOfBirth,
        gender: data.gender,
        yearGroup: data.yearGroup,
        medicalConditions: data.medicalConditions,
        emergencyContacts: {
          create: data.emergencyContacts.map((ec) => ({
            name: ec.name,
            phone: ec.phone,
            relationship: ec.relationship,
          })),
        },
      },
    });
  },

  async updateById(childId: string, data: UpdateChildData) {
    return prisma.child.update({
      where: { id: childId },
      data,
    });
  },

  async softDeleteById(childId: string) {
    // Soft delete — set a deletedAt timestamp by updating and relying on query filters
    // For now we use hard delete; soft delete requires schema migration (Phase 4 concern)
    return prisma.child.delete({ where: { id: childId } });
  },
};

/**
 * @file children.routes.ts
 * @description Fastify route registration for children module. Parent role only.
 * @module src/modules/children/children.routes
 */
import type { FastifyInstance } from 'fastify';
import fp from 'fastify-plugin';

import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { requireRole } from '@/shared/middleware/rbac.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

import { childrenController } from './children.controller.js';
import { ChildIdParamSchema, CreateChildSchema, UpdateChildSchema } from './children.schema.js';

const childResponseSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    firstName: { type: 'string' },
    lastName: { type: 'string' },
    dateOfBirth: { type: 'string' },
    gender: { type: 'string' },
    yearGroup: { type: 'string' },
    medicalConditions: { type: 'string' },
  },
};

const parentGuard = [authMiddleware, requireRole('PARENT')];

async function childrenRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/users/me/children', {
    schema: {
      tags: ['Children'],
      summary: 'Get all children for the current parent',
      security: [{ BearerAuth: [] }],
      response: { 200: { type: 'array', items: childResponseSchema } },
    },
    preHandler: parentGuard,
    handler: childrenController.getChildren,
  });

  app.post('/api/v1/users/me/children', {
    schema: {
      tags: ['Children'],
      summary: 'Add a child profile (requires at least one emergency contact)',
      security: [{ BearerAuth: [] }],
      body: {
        type: 'object',
        required: ['firstName', 'lastName', 'dateOfBirth', 'gender', 'yearGroup', 'emergencyContacts'],
        properties: {
          firstName: { type: 'string' },
          lastName: { type: 'string' },
          dateOfBirth: { type: 'string' },
          gender: { type: 'string' },
          yearGroup: { type: 'string' },
          medicalConditions: { type: 'string' },
          emergencyContacts: {
            type: 'array',
            minItems: 1,
            items: {
              type: 'object',
              required: ['name', 'phone', 'relationship'],
              properties: {
                name: { type: 'string' },
                phone: { type: 'string' },
                relationship: { type: 'string' },
              },
            },
          },
        },
      },
      response: { 201: childResponseSchema },
    },
    preHandler: [...parentGuard, validate({ body: CreateChildSchema })],
    handler: childrenController.createChild,
  });

  app.patch('/api/v1/users/me/children/:childId', {
    schema: {
      tags: ['Children'],
      summary: 'Update a child profile',
      security: [{ BearerAuth: [] }],
      params: {
        type: 'object',
        properties: { childId: { type: 'string' } },
      },
      body: {
        type: 'object',
        properties: {
          firstName: { type: 'string' },
          lastName: { type: 'string' },
          dateOfBirth: { type: 'string' },
          gender: { type: 'string' },
          yearGroup: { type: 'string' },
          medicalConditions: { type: 'string' },
        },
      },
      response: { 200: childResponseSchema },
    },
    preHandler: [
      ...parentGuard,
      validate({ body: UpdateChildSchema, params: ChildIdParamSchema }),
    ],
    handler: childrenController.updateChild,
  });

  app.delete('/api/v1/users/me/children/:childId', {
    schema: {
      tags: ['Children'],
      summary: 'Delete a child profile',
      security: [{ BearerAuth: [] }],
      params: {
        type: 'object',
        properties: { childId: { type: 'string' } },
      },
      response: { 204: { type: 'null' } },
    },
    preHandler: [...parentGuard, validate({ params: ChildIdParamSchema })],
    handler: childrenController.deleteChild,
  });
}

export default fp(childrenRoutes, { name: 'children-routes' });

