 * @module src/modules/notifications/notifications.controller
 */
import type { FastifyReply, FastifyRequest } from 'fastify';

import { notificationsService } from './notifications.service.js';
import type { INotificationIdParam } from './notifications.schema.js';

export const notificationsController = {
  async getNotifications(request: FastifyRequest, reply: FastifyReply) {
    const userId = request.user!.id;
    const notifications = await notificationsService.getForUser(userId);
    await reply.status(200).send(notifications);
  },

  async markAsRead(
    request: FastifyRequest<{ Params: INotificationIdParam }>,
    reply: FastifyReply,
  ) {
    const userId = request.user!.id;
    const { notificationId } = request.params;
    const notification = await notificationsService.markAsRead(notificationId, userId);
    await reply.status(200).send(notification);
  },

  async markAllAsRead(request: FastifyRequest, reply: FastifyReply) {
    const userId = request.user!.id;
    await notificationsService.markAllAsRead(userId);
    await reply.status(200).send({ message: 'All notifications marked as read.' });
  },
};

/**
 * @file notifications.routes.ts
 * @description Fastify route registration for notifications. All routes require auth.
 * @module src/modules/notifications/notifications.routes
 */
import type { FastifyInstance } from 'fastify';
import fp from 'fastify-plugin';

import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

import { notificationsController } from './notifications.controller.js';
import { NotificationIdParamSchema } from './notifications.schema.js';

const notificationSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    type: { type: 'string' },
    title: { type: 'string' },
    body: { type: 'string' },
    isRead: { type: 'boolean' },
    createdAt: { type: 'string' },
  },
};

async function notificationsRoutes(app: FastifyInstance): Promise<void> {
  app.get('/api/v1/notifications', {
    schema: {
      tags: ['Notifications'],
      summary: 'Get all notifications for the current user',
      security: [{ BearerAuth: [] }],
      response: { 200: { type: 'array', items: notificationSchema } },
    },
    preHandler: [authMiddleware],
    handler: notificationsController.getNotifications,
  });

  app.patch('/api/v1/notifications/read-all', {
    schema: {
      tags: ['Notifications'],
      summary: 'Mark all notifications as read',
      security: [{ BearerAuth: [] }],
      response: {
        200: { type: 'object', properties: { message: { type: 'string' } } },
      },
    },
    preHandler: [authMiddleware],
    handler: notificationsController.markAllAsRead,
  });

  app.patch('/api/v1/notifications/:notificationId/read', {
    schema: {
      tags: ['Notifications'],
      summary: 'Mark a single notification as read',
      security: [{ BearerAuth: [] }],
      params: {
        type: 'object',
        properties: { notificationId: { type: 'string' } },
      },
      response: { 200: notificationSchema },
    },
    preHandler: [authMiddleware, validate({ params: NotificationIdParamSchema })],
    handler: notificationsController.markAsRead,
  });
}

export default fp(notificationsRoutes, { name: 'notifications-routes' });

/**
 * @file notifications.service.ts
 * @description Notification business logic — creation (called by event handlers) and retrieval.
 * @module src/modules/notifications/notifications.service
 */
import { AppError } from '@/shared/errors/AppError.js';

import type { Prisma } from '@prisma/client';

import { notificationsRepository } from './notifications.repository.js';
import type { INotificationResponse, NotificationType } from './notifications.schema.js';

function mapToResponse(n: {
  id: string;
  type: string;
  title: string;
  body: string;
  isRead: boolean;
  createdAt: Date;
}): INotificationResponse {
  return {
    id: n.id,
    type: n.type,
    title: n.title,
    body: n.body,
    isRead: n.isRead,
    createdAt: n.createdAt.toISOString(),
  };
}

export const notificationsService = {
  async create(data: {
    userId: string;
    type: NotificationType;
    title: string;
    body: string;
    metadata?: Prisma.InputJsonValue;
  }): Promise<void> {
    await notificationsRepository.createNotification(data);
  },

  async getForUser(userId: string): Promise<INotificationResponse[]> {
    const notifications = await notificationsRepository.findByUserId(userId);
    return notifications.map(mapToResponse);
  },

  async markAsRead(notificationId: string, userId: string): Promise<INotificationResponse> {
    const notification = await notificationsRepository.findByIdAndUserId(notificationId, userId);
    if (!notification) {
      throw new AppError('ACCOUNT_NOT_FOUND', 'Notification not found.', 404);
    }
    const updated = await notificationsRepository.markAsRead(notificationId);
    return mapToResponse(updated);
  },

  async markAllAsRead(userId: string): Promise<void> {
    await notificationsRepository.markAllAsRead(userId);
  },
};

/**
 * @file payments.controller.ts
 * @description HTTP handlers for payment endpoints.
 * @module src/modules/payments/payments.controller
 */
import type { FastifyReply, FastifyRequest } from 'fastify';

import { paymentsService } from './payments.service.js';
import type { ICreatePaymentIntent, IPaymentIdParam } from './payments.schema.js';

export const paymentsController = {
  async createPaymentIntent(
    request: FastifyRequest<{ Body: ICreatePaymentIntent }>,
    reply: FastifyReply,
  ): Promise<void> {
    const result = await paymentsService.createPaymentIntent(request.user!.id, request.body);
    await reply.status(201).send(result);
  },

  async handleWebhook(request: FastifyRequest, reply: FastifyReply): Promise<void> {
    const signature = request.headers['stripe-signature'] as string;

    if (!signature) {
      await reply.status(400).send({ error: 'Missing stripe-signature header' });
      return;
    }

    await paymentsService.handleWebhook(request.body as Buffer, signature);
    await reply.status(200).send({ received: true });
  },

  async getPaymentById(
    request: FastifyRequest<{ Params: IPaymentIdParam }>,
    reply: FastifyReply,
  ): Promise<void> {
    const result = await paymentsService.getPaymentById(request.params.paymentId);
    await reply.status(200).send(result);
  },
};

/**
 * @file payments.routes.ts
 * @description Fastify route registration for payments.
 * The webhook route uses a scoped raw body parser so Stripe signature verification works.
 * @module src/modules/payments/payments.routes
 */
import type { FastifyInstance } from 'fastify';
import fp from 'fastify-plugin';

import { authMiddleware } from '@/shared/middleware/auth.middleware.js';
import { validate } from '@/shared/middleware/validate.js';

import { paymentsController } from './payments.controller.js';
import { CreatePaymentIntentSchema, PaymentIdParamSchema } from './payments.schema.js';

const paymentResponseSchema = {
  type: 'object',
  properties: {
    id: { type: 'string' },
    bookingId: { type: 'string' },
    amount: { type: 'number' },
    currency: { type: 'string' },
    status: { type: 'string', enum: ['pending', 'paid', 'refunded', 'failed'] },
    stripePaymentIntentId: { type: 'string' },
  },
};

async function paymentsRoutes(app: FastifyInstance): Promise<void> {
  // --- Standard JSON routes ---
  app.post('/api/v1/payments/create-intent', {
    schema: {
      tags: ['Payments'],
      summary: 'Create a Stripe PaymentIntent for a booking',
      security: [{ BearerAuth: [] }],
      body: {
        type: 'object',
        required: ['bookingId'],
        properties: { bookingId: { type: 'string' } },
      },
      response: {
        201: {
          type: 'object',
          properties: {
            clientSecret: { type: 'string' },
            paymentId: { type: 'string' },
            amount: { type: 'number', description: 'Amount in pence (GBP)' },
            currency: { type: 'string' },
          },
        },
      },
    },
    preHandler: [authMiddleware, validate({ body: CreatePaymentIntentSchema })],
    handler: paymentsController.createPaymentIntent,
  });

  app.get('/api/v1/payments/:paymentId', {
    schema: {
      tags: ['Payments'],
      summary: 'Get payment status by ID',
      security: [{ BearerAuth: [] }],
      params: { type: 'object', properties: { paymentId: { type: 'string' } } },
      response: { 200: paymentResponseSchema },
    },
    preHandler: [authMiddleware, validate({ params: PaymentIdParamSchema })],
    handler: paymentsController.getPaymentById,
  });

  // --- Webhook route with raw body parser (scoped so it doesn't affect other routes) ---
  await app.register(async (webhookScope) => {
    webhookScope.addContentTypeParser(
      'application/json',
      { parseAs: 'buffer' },
      (_req, body, done) => {
        done(null, body);
      },
    );

    webhookScope.post('/api/v1/payments/webhook', {
      schema: {
        tags: ['Payments'],
        summary: 'Stripe webhook handler — do not call manually',
        response: {
          200: { type: 'object', properties: { received: { type: 'boolean' } } },
        },
      },
      handler: paymentsController.handleWebhook,
    });
  });
}

export default fp(paymentsRoutes, { name: 'payments-routes' });

/**
 * @file payments.schema.ts
 * @description Zod schemas for payment endpoints.
 *
 * Endpoints:
 *   POST /api/v1/payments/create-intent  → body: CreatePaymentIntentSchema → response: PaymentIntentResponse
 *   POST /api/v1/payments/webhook        → raw body (Stripe webhook) → response: 200
 *   GET  /api/v1/payments/:paymentId     → response: PaymentResponse
 *
 * PaymentStatus enum map (Prisma → API):
 *   PENDING  → 'pending'
 *   PAID     → 'paid'
 *   REFUNDED → 'refunded'
 *   FAILED   → 'failed'
 *
 * @module src/modules/payments/payments.schema
 */
import { z } from 'zod';
import type { PaymentStatus } from '@prisma/client';

export const PAYMENT_STATUS_MAP: Record<PaymentStatus, string> = {
  PENDING: 'pending',
  PAID: 'paid',
  REFUNDED: 'refunded',
  FAILED: 'failed',
};

export const CreatePaymentIntentSchema = z.object({
  bookingId: z.string().min(1),
});

export const PaymentIdParamSchema = z.object({
  paymentId: z.string().min(1),
});

export const PaymentResponseSchema = z.object({
  id: z.string(),
  bookingId: z.string(),
  amount: z.number().nonnegative(),
  currency: z.string(),
  status: z.enum(['pending', 'paid', 'refunded', 'failed']),
  stripePaymentIntentId: z.string(),
});

export const PaymentIntentResponseSchema = z.object({
  clientSecret: z.string(),
  paymentId: z.string(),
  amount: z.number(),
  currency: z.string(),
});

export type ICreatePaymentIntent = z.infer<typeof CreatePaymentIntentSchema>;
export type IPaymentIdParam = z.infer<typeof PaymentIdParamSchema>;
export type IPaymentResponse = z.infer<typeof PaymentResponseSchema>;
export type IPaymentIntentResponse = z.infer<typeof PaymentIntentResponseSchema>;

/**
 * @file payments.service.ts
 * @description Stripe payment orchestration. Idempotent intent creation and webhook handling.
 * @module src/modules/payments/payments.service
 */
import type Stripe from 'stripe';

import { AppError } from '@/shared/errors/AppError.js';
import { env } from '@/config/env.js';
import { eventBus } from '@/shared/events/event-bus.js';
import { EventType } from '@/shared/events/event-types.js';
import { logger } from '@/shared/infrastructure/logger.js';
import { getStripeClient } from '@/shared/utils/stripe.js';

import { mapToPaymentResponse } from './payments.domain.js';
import { paymentsRepository } from './payments.repository.js';
import type { ICreatePaymentIntent, IPaymentIntentResponse, IPaymentResponse } from './payments.schema.js';

export const paymentsService = {
  async createPaymentIntent(
    userId: string,
    input: ICreatePaymentIntent,
  ): Promise<IPaymentIntentResponse> {
    const booking = await paymentsRepository.findBookingById(input.bookingId, userId);

    if (!booking) {
      throw new AppError('BOOKING_NOT_FOUND', 'Booking not found.', 404);
    }

    if (booking.status === 'CANCELLED') {
      throw new AppError('BOOKING_ALREADY_CANCELLED', 'Cannot pay for a cancelled booking.', 409);
    }

    // Idempotency — return existing payment intent if already created for this booking
    const existingPayment = await paymentsRepository.findByBookingId(input.bookingId);
    if (existingPayment) {
      const stripe = getStripeClient();
      const intent = await stripe.paymentIntents.retrieve(
        existingPayment.stripePaymentIntentId,
      );
      return {
        clientSecret: intent.client_secret!,
        paymentId: existingPayment.id,
        amount: Math.round(existingPayment.amount.toNumber() * 100),
        currency: existingPayment.currency,
      };
    }

    const stripe = getStripeClient();
    const amountInPence = Math.round(booking.session.price.toNumber() * 100);

    const intent = await stripe.paymentIntents.create(
      {
        amount: amountInPence,
        currency: 'gbp',
        metadata: { bookingId: booking.id, userId },
      },
      { idempotencyKey: `booking-${booking.id}` },
    );

    const payment = await paymentsRepository.create({
      bookingId: booking.id,
      stripePaymentIntentId: intent.id,
      amount: booking.session.price,
      currency: 'gbp',
    });

    return {
      clientSecret: intent.client_secret!,
      paymentId: payment.id,
      amount: amountInPence,
      currency: 'gbp',
    };
  },

  async handleWebhook(rawBody: Buffer, signature: string): Promise<void> {
    if (!env.STRIPE_WEBHOOK_SECRET) {
      throw new AppError('SERVER_ERROR', 'Stripe webhook secret is not configured.', 500);
    }

    const stripe = getStripeClient();

    let event: Stripe.Event;
    try {
      event = stripe.webhooks.constructEvent(rawBody, signature, env.STRIPE_WEBHOOK_SECRET);
    } catch {
      throw new AppError('VALIDATION_ERROR', 'Invalid Stripe webhook signature.', 400);
    }

    logger.info({ type: event.type, id: event.id }, 'Stripe webhook received');

    switch (event.type) {
      case 'payment_intent.succeeded': {
        const intent = event.data.object as Stripe.PaymentIntent;
        const payment = await paymentsRepository.findByStripeIntentId(intent.id);
        if (!payment) {
          logger.warn({ intentId: intent.id }, 'Webhook: payment record not found');
          return;
        }
        if (payment.status === 'PAID') return; // idempotency — already processed

        await paymentsRepository.updateStatusByStripeIntentId(intent.id, 'PAID');

        eventBus.emit(EventType.PAYMENT_SUCCEEDED, {
          paymentId: payment.id,
          bookingId: payment.bookingId,
          userId: intent.metadata?.userId ?? '',
        });
        break;
      }

      case 'payment_intent.payment_failed': {
        const intent = event.data.object as Stripe.PaymentIntent;
        const payment = await paymentsRepository.findByStripeIntentId(intent.id);
        if (!payment) return;
        if (payment.status === 'FAILED') return;

        await paymentsRepository.updateStatusByStripeIntentId(intent.id, 'FAILED');

        eventBus.emit(EventType.PAYMENT_FAILED, {
          paymentId: payment.id,
          bookingId: payment.bookingId,
          userId: intent.metadata?.userId ?? '',
        });
        break;
      }

      default:
        logger.debug({ type: event.type }, 'Stripe webhook: unhandled event type');
    }
  },

  async getPaymentById(paymentId: string): Promise<IPaymentResponse> {
    const payment = await paymentsRepository.findById(paymentId);
    if (!payment) {
      throw new AppError('ACCOUNT_NOT_FOUND', 'Payment not found.', 404);
    }
    return mapToPaymentResponse(payment);
  },
};

